script:
import { agent, skill } from '@tinyfish/cli';

export default agent({
  name: 'shopify-orders-export',
  inputs: { date_range: { type: 'string', default: 'yesterday' } },
  async run({ input, browser }) {
    await browser.navigate('https://admin.shopify.com/orders');
    await skill('open-filters').run(browser);
    await skill('set-date-range').run(browser, { value: input.date_range });
    const csv = await skill('export-csv').run(browser);
    return { csv_url: csv.url, row_count: csv.rows };
  }
});

